public boolean validTree(int n, int[][] edges) {
    if (edges.length != n - 1) return false; // quick check
    List<List<Integer>> adj = new ArrayList<>();
    for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
    for (int[] e : edges) {
        adj.get(e[0]).add(e[1]);
        adj.get(e[1]).add(e[0]);
    }
    boolean[] visited = new boolean[n];
    if (!dfs(adj, visited, 0, -1)) return false;
    for (boolean v : visited) if (!v) return false;
    return true;
}

private boolean dfs(List<List<Integer>> adj, boolean[] visited, int node, int parent) {
    visited[node] = true;
    for (int neighbor : adj.get(node)) {
        if (neighbor == parent) continue;
        if (visited[neighbor]) return false;
        if (!dfs(adj, visited, neighbor, node)) return false;
    }
    return true;
}

